import redis

class LuaExecutor:
    def __init__(self, host='localhost', port=6379):
        self.redis_client = redis.Redis(host=host, port=port)

    def execute_lua(self, lua_code, params=None):
        if not isinstance(lua_code, str) or not lua_code.strip():
            raise ValueError("Invalid Lua code")

        try:
            result = self.redis_client.eval(lua_code, 0, *params)
            return result
        except redis.exceptions.RedisError as e:
            print(f"Redis error: {e}")
            return None

def main():
    executor = LuaExecutor()

    while True:
        lua_code = input("Enter Lua code (or 'quit' to exit): ")
        if lua_code.lower() == 'quit':
            break

        try:
            params = input("Enter parameters (comma-separated values): ").split(',')
            params = [param.strip() for param in params]
            result = executor.execute_lua(lua_code, params)
            print(result)
        except ValueError as e:
            print(f"Error: {e}")

if __name__ == "__main__":
    main()